  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.call_profiles_processor_async()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM net.http_post(
    url := current_setting('app.settings.supabase_url', true) || '/functions/v1/profiles-processor',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key', true),
      'Content-Type', 'application/json'
    ),
    body := '{}'::jsonb
  );
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.sub_account_bonus_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_prev numeric := COALESCE((CASE WHEN TG_OP = 'UPDATE' THEN OLD.available_balance ELSE NULL END), 0);
  v_new numeric := COALESCE(NEW.available_balance, 0);
BEGIN
  -- Only USD rows and only when crossing strictly above 3
  IF NEW.currency = 'USD' AND v_new > 3 AND COALESCE(v_prev, 0) <= 3 THEN
    PERFORM public.award_welcome_bonus(NEW.wallet_address, 3, 100);
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.sub_account_bonus_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_prev numeric := COALESCE((CASE WHEN TG_OP = 'UPDATE' THEN OLD.available_balance ELSE NULL END), 0);
  v_new numeric := COALESCE(NEW.available_balance, 0);
BEGIN
  -- Only USD rows and only when crossing strictly above 3
  IF NEW.currency = 'USD' AND v_new > 3 AND COALESCE(v_prev, 0) <= 3 THEN
    PERFORM public.award_welcome_bonus(NEW.wallet_address, 3, 100);
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.sub_account_balances_sync_ids()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.user_id IS NOT NULL THEN
    NEW.user_id := 'prize:pid:' || lower(replace(NEW.user_id::text, 'prize:pid:', ''));
    NEW.canonical_user_id := NEW.user_id;
  ELSIF NEW.canonical_user_id IS NOT NULL THEN
    NEW.canonical_user_id := 'prize:pid:' || lower(replace(NEW.canonical_user_id::text, 'prize:pid:', ''));
    NEW.user_id := NEW.canonical_user_id;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.trigger_check_competition_sold_out()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'INSERT' AND NEW.competition_id IS NOT NULL THEN
    PERFORM check_and_mark_competition_sold_out(NEW.competition_id);
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tickets_finalize_spend_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_finalized boolean;
  v_amount numeric;
  v_cuid text;
  v_provider text;
BEGIN
  -- Only act after insert or update to a finalized state
  v_finalized := (NEW.status IN ('sold','purchased')) AND NEW.payment_amount IS NOT NULL;
  IF NOT v_finalized THEN
    RETURN NEW;
  END IF;

  v_amount := NEW.payment_amount;
  v_cuid := public._ticket_cuid(NEW.user_id, NEW.canonical_user_id, NEW.wallet_address);
  v_provider := NEW.payment_provider; -- may be null; acceptable

  -- Ensure we only process once per ticket id
  -- Type-safe comparison: match by canonical_user_id when present, otherwise compare user_id::text
  PERFORM 1 FROM public.user_transactions ut
  WHERE ut.type = 'entry'
    AND ut.status = 'completed'
    AND ut.amount = v_amount
    AND (ut.order_id = NEW.order_id OR (NEW.order_id IS NULL AND ut.order_id IS NULL))
    AND (ut.description = NEW.id::text OR ut.description IS NULL)
    AND (
      (ut.canonical_user_id IS NOT NULL AND ut.canonical_user_id = v_cuid)
      OR (ut.canonical_user_id IS NULL AND ut.user_id IS NOT NULL AND ut.user_id::text = v_cuid)
    );
  IF FOUND THEN
    RETURN NEW;
  END IF;

  -- Insert transaction (v_cuid is canonical text id)
  PERFORM public._insert_user_spend_tx(v_cuid, v_amount, NEW.competition_id, NEW.order_id, NEW.id, v_provider, NEW.wallet_address);

  -- Deduct from balance using canonical id text
  PERFORM public._deduct_sub_account_balance(v_cuid, v_amount);

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION util.trg_set_cuid_from_context()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL THEN
    NEW.canonical_user_id := util.resolve_canonical_user_id(
      NEW.wallet_address,
      COALESCE(NEW.privy_user_id, NEW.user_privy_id)
    );
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_sync_joincompetition_from_tickets()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_tx text;
  v_new_tx text;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_new_tx := NEW.payment_tx_hash;
    IF v_new_tx IS NOT NULL THEN
      PERFORM public.upsert_joincompetition_by_tx(v_new_tx);
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    v_old_tx := OLD.payment_tx_hash;
    v_new_tx := NEW.payment_tx_hash;
    IF v_old_tx IS NOT DISTINCT FROM v_new_tx THEN
      IF v_new_tx IS NOT NULL THEN
        PERFORM public.upsert_joincompetition_by_tx(v_new_tx);
      END IF;
    ELSE
      IF v_old_tx IS NOT NULL THEN
        PERFORM public.upsert_joincompetition_by_tx(v_old_tx);
      END IF;
      IF v_new_tx IS NOT NULL THEN
        PERFORM public.upsert_joincompetition_by_tx(v_new_tx);
      END IF;
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    v_old_tx := OLD.payment_tx_hash;
    IF v_old_tx IS NOT NULL THEN
      DELETE FROM public.joincompetition jc
      WHERE jc.transactionhash IS NOT DISTINCT FROM v_old_tx
        AND jc.competitionid::text = OLD.competition_id::text
        AND NOT EXISTS (
          SELECT 1 FROM public.tickets t
          WHERE t.payment_tx_hash IS NOT DISTINCT FROM v_old_tx
            AND t.competition_id = OLD.competition_id
        );
    END IF;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.tickets_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.complete_topup_on_webhook_ref()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- Only for coinbase topups
  IF (COALESCE(NEW.provider,'') = 'coinbase' AND COALESCE(NEW.type,'') = 'topup') THEN
    -- If webhook_ref is present and status is not already completed, flip to completed
    IF COALESCE(NEW.webhook_ref, '') <> '' AND NEW.status <> 'completed' THEN
      NEW.status := 'completed';
      NEW.completed_at := COALESCE(NEW.completed_at, NOW());
    END IF;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.complete_topup_on_webhook_ref()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- Only for coinbase topups
  IF (COALESCE(NEW.provider,'') = 'coinbase' AND COALESCE(NEW.type,'') = 'topup') THEN
    -- If webhook_ref is present and status is not already completed, flip to completed
    IF COALESCE(NEW.webhook_ref, '') <> '' AND NEW.status <> 'completed' THEN
      NEW.status := 'completed';
      NEW.completed_at := COALESCE(NEW.completed_at, NOW());
    END IF;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.fn_credit_sub_account_on_instant_wallet_topup()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_user text;
  v_currency text;
  v_amount numeric;
BEGIN
  IF NOT (
    NEW.payment_provider = 'instant_wallet_topup' AND
    NEW.status = 'completed' AND
    COALESCE(NEW.payment_status, 'confirmed') IN ('confirmed','succeeded') AND
    NEW.amount > 0
  ) THEN
    RETURN NEW;
  END IF;

  v_user := NEW.canonical_user_id;
  v_currency := CASE UPPER(COALESCE(NEW.currency, 'USD')) WHEN 'USDC' THEN 'USD' ELSE UPPER(NEW.currency) END;
  IF v_currency IS NULL THEN v_currency := 'USD'; END IF;
  v_amount := NEW.amount;

  INSERT INTO public.sub_account_balances (
    canonical_user_id, currency, available_balance, pending_balance, last_updated
  ) VALUES (
    v_user, v_currency, 0, COALESCE((SELECT pending_balance FROM public.sub_account_balances WHERE canonical_user_id = v_user AND currency = v_currency), 0), now()
  )
  ON CONFLICT (canonical_user_id, currency) DO NOTHING;

  UPDATE public.sub_account_balances
     SET available_balance = COALESCE(available_balance, 0) + v_amount,
         last_updated = now()
   WHERE canonical_user_id = v_user AND currency = v_currency;

  -- Removed ledger insert to avoid unrelated triggers
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION util.finalize_pending_user_transactions()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_curr_balance numeric;
BEGIN
  IF NEW.status = 'pending' THEN
    SELECT COALESCE(sab.available_balance, 0)
      INTO v_curr_balance
      FROM public.sub_account_balances sab
     WHERE sab.canonical_user_id = NEW.canonical_user_id
       AND sab.currency = NEW.currency
     LIMIT 1;

    NEW.balance_before := COALESCE(v_curr_balance, 0);
    NEW.balance_after  := COALESCE(v_curr_balance, 0) + COALESCE(NEW.amount, 0);
    NEW.status := 'completed';
    NEW.completed_at := NOW();
    NEW.posted_to_balance := true;

    -- Upsert balance atomically
    INSERT INTO public.sub_account_balances (
      user_id, canonical_user_id, currency, available_balance, pending_balance, last_updated
    ) VALUES (
      NEW.user_id, NEW.canonical_user_id, NEW.currency, COALESCE(NEW.amount,0), 0, NOW()
    )
    ON CONFLICT (canonical_user_id, currency)
    DO UPDATE SET available_balance = public.sub_account_balances.available_balance + EXCLUDED.available_balance,
                  last_updated = NOW();
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.repair_topup_provider_and_status()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  has_coinbase boolean := false;
  ev_id_suffix text;
  new_meta jsonb;
  new_status text;
BEGIN
  -- Only for topups; do not affect entries
  IF NEW.type <> 'topup' THEN
    RETURN NEW;
  END IF;

  -- Determine if Coinbase webhook exists for this transaction
  ev_id_suffix := NEW.id::text;

  SELECT EXISTS (
    SELECT 1
    FROM public.payment_webhook_events pwe
    WHERE pwe.provider = 'coinbase-commerce'
      AND (
        (NEW.charge_id IS NOT NULL AND pwe.transaction_id = NEW.charge_id)
        OR (pwe.event_id LIKE 'TOPUP_%_' || ev_id_suffix)
      )
  ) INTO has_coinbase;

  new_meta := COALESCE(NEW.metadata, '{}'::jsonb);

  IF has_coinbase THEN
    IF COALESCE(new_meta->>'provider', '') <> 'coinbase' THEN
      new_meta := new_meta || jsonb_build_object('provider', 'coinbase');
    END IF;
  END IF;

  -- Auto-confirm when posted_to_balance is true
  IF NEW.posted_to_balance IS TRUE THEN
    new_status := 'confirmed';
  ELSE
    new_status := COALESCE(NEW.payment_status, 'pending');
  END IF;

  IF new_meta IS DISTINCT FROM NEW.metadata OR new_status IS DISTINCT FROM NEW.payment_status THEN
    NEW.metadata := new_meta;
    NEW.payment_status := new_status;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.sync_identity_columns()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_row_json jsonb;
    v_canonical_user canonical_users%ROWTYPE;
    v_lookup_id text;
    v_found boolean := false;
BEGIN
    -- Convert the incoming row to JSON to check available fields
    v_row_json := to_jsonb(NEW);

    -- Only proceed if we need to fill in missing identity information
    -- Check if canonical_user_id is NULL and we have something to look up
    IF (v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NULL) OR
       (v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NULL) THEN

        -- Try lookup by canonical_user_id first (if present and not null)
        IF v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'canonical_user_id';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE canonical_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by privy_user_id if not found and field exists
        IF NOT v_found AND v_row_json ? 'privy_user_id' AND (v_row_json->>'privy_user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'privy_user_id';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE privy_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by user_id if not found and field exists (might be a wallet or canonical ID)
        IF NOT v_found AND v_row_json ? 'user_id' AND (v_row_json->>'user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'user_id';
            -- Try as canonical_user_id first
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE canonical_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;

            -- Try as wallet_address (case insensitive)
            IF NOT v_found AND v_lookup_id LIKE '0x%' THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE LOWER(wallet_address) = LOWER(v_lookup_id)
                   OR LOWER(base_wallet_address) = LOWER(v_lookup_id)
                LIMIT 1;
                v_found := FOUND;
            END IF;

            -- Try as privy_user_id
            IF NOT v_found THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE privy_user_id = v_lookup_id
                LIMIT 1;
                v_found := FOUND;
            END IF;

            -- Try as uid
            IF NOT v_found THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE uid::text = v_lookup_id
                LIMIT 1;
                v_found := FOUND;
            END IF;
        END IF;

        -- Try lookup by wallet_address if not found and field exists
        IF NOT v_found AND v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'wallet_address';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE LOWER(wallet_address) = LOWER(v_lookup_id)
               OR LOWER(base_wallet_address) = LOWER(v_lookup_id)
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by uid if not found and field exists
        IF NOT v_found AND v_row_json ? 'uid' AND (v_row_json->>'uid') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'uid';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE uid::text = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- If we found a matching canonical user, enrich the row
        IF v_found THEN
            -- Fill canonical_user_id if column exists and is NULL
            IF v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NULL THEN
                IF v_canonical_user.canonical_user_id IS NOT NULL THEN
                    NEW.canonical_user_id := v_canonical_user.canonical_user_id;
                END IF;
            END IF;

            -- Fill wallet_address if column exists and is NULL
            IF v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NULL THEN
                IF v_canonical_user.wallet_address IS NOT NULL THEN
                    NEW.wallet_address := v_canonical_user.wallet_address;
                ELSIF v_canonical_user.base_wallet_address IS NOT NULL THEN
                    NEW.wallet_address := v_canonical_user.base_wallet_address;
                END IF;
            END IF;
        END IF;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_transactions_post_to_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_delta numeric;
  v_before numeric;
  v_after numeric;
  v_curr text;
  v_desc text;
BEGIN
  -- Only act when status = completed and not yet posted
  IF NEW.status <> 'completed' OR COALESCE(NEW.posted_to_balance, false) IS TRUE THEN
    RETURN NEW;
  END IF;

  IF NEW.amount IS NULL OR NEW.amount <= 0 THEN
    RAISE EXCEPTION 'Amount must be positive';
  END IF;

  -- CRITICAL FIX: Skip external crypto payments
  IF NEW.payment_provider IN (
    'base_account',
    'coinbase_commerce',
    'coinbase',
    'privy_base_wallet',
    'onchainkit',
    'onchainkit_checkout'
  ) THEN
    NEW.posted_to_balance := true;
    NEW.completed_at := COALESCE(NEW.completed_at, now());
    RETURN NEW;
  END IF;

  -- ONLY process balance payments and onramp top-ups
  IF NEW.payment_provider NOT IN ('balance', 'onramp', 'coinbase_onramp') THEN
    NEW.posted_to_balance := true;
    NEW.completed_at := COALESCE(NEW.completed_at, now());
    RETURN NEW;
  END IF;

  v_curr := COALESCE(NEW.currency, 'USDC');
  v_delta := public._wallet_delta_from_txn(NEW.type, NEW.amount);

  -- Apply to wallet
  SELECT balance_before, balance_after
    INTO v_before, v_after
  FROM public._apply_wallet_delta(NEW.canonical_user_id, v_curr, v_delta);

  -- Compose description
  v_desc := COALESCE(NEW.description,
            CASE WHEN lower(NEW.type) IN ('topup','top_up','top-up') THEN 'Wallet top up'
                 WHEN lower(NEW.type) IN ('entry','entry_payment','purchase') THEN 'Competition entry'
                 ELSE 'User transaction'
            END);

  -- Insert ledger row
  INSERT INTO public.balance_ledger (
    canonical_user_id,
    transaction_type,
    amount,
    currency,
    balance_before,
    balance_after,
    reference_id,
    description,
    created_at,
    top_up_tx_id
  ) VALUES (
    NEW.canonical_user_id,
    NEW.type,
    NEW.amount,
    v_curr,
    v_before,
    v_after,
    NEW.id::text,
    v_desc,
    now(),
    COALESCE(NEW.tx_id, NEW.payment_tx_hash)
  );

  NEW.posted_to_balance := true;
  NEW.completed_at := COALESCE(NEW.completed_at, now());
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION util.trg_set_cuid_from_context()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL THEN
    NEW.canonical_user_id := util.resolve_canonical_user_id(
      NEW.wallet_address,
      COALESCE(NEW.privy_user_id, NEW.user_privy_id)
    );
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_transactions_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_tx_autocomplete_if_expired()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'pending' AND NEW.expires_at IS NOT NULL AND NEW.expires_at <= NOW() THEN
    NEW.status := 'completed';
    NEW.completed_at := NOW();
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_tx_autocomplete_if_expired()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'pending' AND NEW.expires_at IS NOT NULL AND NEW.expires_at <= NOW() THEN
    NEW.status := 'completed';
    NEW.completed_at := NOW();
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_tx_before_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.type := lower(COALESCE(NEW.type, 'entry'));
  NEW.status := lower(COALESCE(NEW.status, 'pending'));

  IF NEW.status = 'pending' AND NEW.expires_at IS NULL THEN
    NEW.expires_at := NOW() + INTERVAL '2 minutes';
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_tx_guard_no_double_post()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.posted_to_balance = true AND NEW.status = 'completed' THEN
    NEW.posted_to_balance := true;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.post_user_transaction_to_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_currency text;
  v_effect numeric;
  v_bal_id uuid;
  v_currency_final text;
BEGIN
  -- Skip if already posted to balance
  IF NEW.posted_to_balance = true THEN
    RETURN NEW;
  END IF;

  -- Skip if not completed
  IF NEW.status <> 'completed' THEN
    RETURN NEW;
  END IF;

  -- CRITICAL FIX: Skip external crypto payments
  IF NEW.payment_provider IN (
    'base_account',
    'coinbase_commerce',
    'coinbase',
    'privy_base_wallet',
    'onchainkit',
    'onchainkit_checkout'
  ) THEN
    NEW.posted_to_balance := true;
    RETURN NEW;
  END IF;

  -- ONLY process balance payments and onramp top-ups
  IF NEW.payment_provider NOT IN ('balance', 'onramp', 'coinbase_onramp') THEN
    NEW.posted_to_balance := true;
    RETURN NEW;
  END IF;

  -- Determine currency
  BEGIN
    EXECUTE 'SELECT ($1).' || quote_ident('currency') INTO v_currency USING NEW;
  EXCEPTION WHEN others THEN
    v_currency := NULL;
  END;
  v_currency_final := COALESCE(v_currency, NEW.metadata->>'currency', 'USD');

  -- Calculate balance effect
  IF NEW.type IN ('entry','payment') THEN
    v_effect := - NEW.amount;
  ELSIF NEW.type IN ('topup','refund','adjustment') THEN
    v_effect := NEW.amount;
  ELSE
    v_effect := 0;
  END IF;

  -- Only proceed if there's an effect
  IF v_effect != 0 THEN
    PERFORM public.ensure_sub_account_balance_row(NEW.canonical_user_id, v_currency_final);

    SELECT id INTO v_bal_id
    FROM public.sub_account_balances
    WHERE canonical_user_id = NEW.canonical_user_id
      AND currency = v_currency_final
    LIMIT 1;

    UPDATE public.sub_account_balances b
    SET available_balance = b.available_balance + v_effect,
        last_updated = NOW()
    WHERE b.id = v_bal_id;
  END IF;

  NEW.posted_to_balance := true;
  IF NEW.completed_at IS NULL THEN
    NEW.completed_at := NOW();
  END IF;
  RETURN NEW;
END;
$function$

